@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun DropdownMenuBox(
    items: List<String>,
    onItemSelected: (String) -> Unit,
    labelId: Int,
    modifier: Modifier = Modifier,
    selectedText: String = "",
) {
    var expanded by remember { mutableStateOf(value = false) }
    var textFieldSize by remember { mutableStateOf(value = Size.Zero) }

    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = modifier
            .fillMaxWidth()
            .padding(vertical = 8.dp)
    ) {
        Box {
            DropdownTextField(
                selectedText = selectedText,
                expanded = expanded,
                labelId = labelId,
                onSizeChanged = { textFieldSize = it }
            )
            Box(
                modifier = Modifier
                    .matchParentSize()
                    .clickable(onClick = { expanded = !expanded })
            )
        }

        DropdownMenu(
            expanded = expanded,
            onDismissRequest = { expanded = false },
            modifier = Modifier.width(width = with(LocalDensity.current) { textFieldSize.width.toDp() })
        ) {
            items.forEach { label ->
                DropdownMenuItem(
                    text = { Text(text = label, style = MaterialTheme.typography.bodyLarge) },
                    onClick = {
                        onItemSelected(label)
                        expanded = false
                    }
                )
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun DropdownTextField(
    selectedText: String,
    expanded: Boolean,
    labelId: Int,
    onSizeChanged: (Size) -> Unit
) {
    OutlinedTextField(
        value = selectedText.trim(),
        onValueChange = { },
        readOnly = true,
        modifier = Modifier
            .fillMaxWidth()
            .onGloballyPositioned { coordinates ->
                onSizeChanged(coordinates.size.toSize())
            },
        label = {
            Text(
                text = stringResource(id = labelId),
                style = MaterialTheme.typography.bodyLarge.copy(
                    fontSize = MaterialTheme.typography.bodyLarge.fontSize * 1.08f,
                    fontWeight = FontWeight.Bold
                )
            )
        },
        trailingIcon = {
            ExposedDropdownMenuDefaults.TrailingIcon(expanded = expanded)
        },
        textStyle = MaterialTheme.typography.bodyLarge.copy(fontWeight = FontWeight.Bold),
        isError = selectedText.trim().isEmpty() && labelId == R.string.allowance,
        enabled = true,
        shape = RoundedCornerShape(size = 12.dp),
        colors = OutlinedTextFieldDefaults.colors(
            disabledTextColor = MaterialTheme.colorScheme.onSurface,
            disabledBorderColor = MaterialTheme.colorScheme.outline,
            disabledLabelColor = MaterialTheme.colorScheme.onSurfaceVariant,
        )
    )
}

