@Composable
internal fun WorkdayListSection(
    items: List<SingleProjectState>,
    selectedIndex: Int,
    onItemSelected: (Int) -> Unit,
    modifier: Modifier = Modifier
) {
    val listState = rememberLazyListState()

    if (items.isEmpty()) {
        Box(
            modifier = modifier.fillMaxWidth(),
            contentAlignment = Alignment.Center
        ) {
            Text(
                text = stringResource(id = R.string.no_projects_available),
                style = MaterialTheme.typography.bodyLarge,
                textAlign = TextAlign.Center,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                modifier = Modifier.padding(all = 32.dp)
            )
        }
    } else {
        ElevatedCard(
            modifier = modifier.fillMaxWidth(),
            elevation = CardDefaults.elevatedCardElevation(defaultElevation = 8.dp)
        ) {
            LazyColumn(
                modifier = Modifier
                    .fillMaxWidth()
                    .lazyVerticalScrollbar(listState = listState)
                    .clip(shape = RoundedCornerShape(size = FIELD_CORNER_RADIUS))
                    .border(
                        width = 1.dp,
                        color = MaterialTheme.colorScheme.outlineVariant,
                        shape = RoundedCornerShape(size = FIELD_CORNER_RADIUS)
                    )
                    .selectableGroup(),
                state = listState,
                verticalArrangement = Arrangement.spacedBy(space = 2.dp)
            ) {
                items(
                    items = items,
                    key = { it.projectName }
                ) { item ->
                    ProjectListItem(
                        item = item,
                        isSelected = selectedIndex == item.index,
                        onClick = { onItemSelected(item.index) }
                    )
                }
            }
        }
    }
}

